import { graphql } from "gatsby"
import HomepageComponent from "../../gatsby-theme-minimal-blog/@lekoarts/gatsby-theme-minimal-blog-core/components/homepage"

export default HomepageComponent

export const query = graphql`
  query ($formatString: String!) {
    allPost(sort: { fields: date, order: DESC }, limit: 3) {
      nodes {
        slug
        title
        date(formatString: $formatString)
        excerpt
        description
        tags {
          name
          slug
        }
      }
    }
    allProject(sort: { fields: startDate, order: DESC }, limit: 3) {
      nodes {
        slug
        title
        startDate(formatString: "YYYY.MM")
        endDate(formatString: "YYYY.MM")
        excerpt
        description
        tags {
          name
          slug
        }
      }
    }
  }
`
