/** @jsx jsx */
import * as React from "react"
import { jsx, Link as TLink, Box } from "theme-ui"
import { Link } from "gatsby"
import ItemTags from "./item-tags"

type Props = {
  projects: {
    slug: string
    title: string
    startDate: string
    endDate: string
    excerpt: string
    description: string
    tags?: {
      name: string
      slug: string
    }[]
  }[]
  className?: string
  showTags?: boolean
}

// type ItemProps = {
//   project: {
//     slug: string
//     title: string
//     startDate: string
//     endDate: string
//     excerpt: string
//     description: string
//     tags?: {
//       name: string
//       slug: string
//     }[]
//   }
//   showTags?: boolean
// }

const ProjectListing = ({ projects, className = ``, showTags = true }: Props) => (
  <section sx={{ mb: [5, 6, 7] }} className={className}>
    {projects.map((project) => (
      <Box mb={4}>
        <TLink as={Link} to={project.slug} sx={{ fontSize: [1, 2, 3], color: `text` }}>
          {project.title}
        </TLink>
        <p sx={{ color: `secondary`, my: 1, a: { color: `secondary` }, fontSize: [1, 1, 1]}}>
          {project.tags && showTags && (
            <React.Fragment>
              {project.tags.map((tag, i) => (
                <React.Fragment key={tag.slug}>
                  <span sx={{backgroundColor: `lightgray`, borderRadius: `1em`, padding: `0em 0.5em`}}>
                    {tag.name}
                  </span>
                  {` `}
                </React.Fragment>
              ))}
              {/* <ItemTags tags={project.tags} /> */}
            </React.Fragment>
          )}
        </p>
        <p sx={{ color: `secondary`, mt: 1, a: { color: `secondary` }, fontSize: [1, 1, 1] }}>
          <time>{project.startDate} {` — `} {project.endDate}</time>
        </p>
      </Box>
    ))}
  </section>
)

export default ProjectListing
